import React, { useEffect, useState } from "react";
import api from "../api/api"; // ✅ Usamos tu instancia de api con el token
import "bootstrap/dist/css/bootstrap.min.css";
import Pagination from "../components/Pagination";
import { FaHistory, FaSync, FaFileInvoiceDollar, FaEye, FaUser, FaBox } from "react-icons/fa";

export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // Estado para el modal de detalle
  const [ventaSeleccionada, setVentaSeleccionada] = useState(null);

  useEffect(() => {
    cargarHistorial();
  }, []);

  const cargarHistorial = async () => {
    try {
      setLoading(true);
      const res = await api.get("/ventas"); // ✅ Ajustado a tu ruta real
      setVentas(res.data || []);
    } catch (error) {
      console.error("❌ Error al cargar historial:", error);
    } finally {
      setLoading(false);
    }
  };

  // Lógica de Paginación
  const indexLast = currentPage * itemsPerPage;
  const indexFirst = indexLast - itemsPerPage;
  const ventasMostradas = ventas.slice(indexFirst, indexLast);

  if (loading) {
    return (
      <div className="container mt-5 text-center">
        <div className="spinner-border text-primary" role="status"></div>
        <p className="mt-2 fw-bold text-secondary">Cargando historial de ventas...</p>
      </div>
    );
  }

  return (
    <div className="container-fluid p-4 pb-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="fw-bold text-dark mb-0">
          <FaHistory className="me-2 text-primary" /> Historial de Ventas
        </h3>
        <button className="btn btn-primary shadow-sm d-flex align-items-center rounded-pill" onClick={cargarHistorial}>
          <FaSync className="me-2" /> Actualizar Datos
        </button>
      </div>

      <div className="card shadow-sm border-0 overflow-hidden rounded-4">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="bg-dark text-white">
              <tr className="text-center">
                <th className="py-3">Factura #</th>
                <th className="py-3">Fecha</th>
                <th className="py-3 text-start ps-4">Cliente</th>
                <th className="py-3">Total</th>
                <th className="py-3">Acciones</th>
              </tr>
            </thead>
            <tbody>
              {ventasMostradas.length > 0 ? (
                ventasMostradas.map((v) => (
                  <tr key={v._id} className="text-center border-bottom">
                    <td className="fw-bold text-primary">
                      #{v._id?.slice(-6).toUpperCase() || "S/N"}
                    </td>
                    <td className="text-muted small">
                      {new Date(v.createdAt).toLocaleString()}
                    </td>
                    <td className="text-start ps-4 fw-semibold">
                      {/* ✅ Accedemos al cliente poblado o al nombre directo */}
                      <FaUser className="me-2 text-muted small" />
                      {v.cliente_id?.nombre || v.nombre_cliente || "Consumidor Final"}
                    </td>
                    <td className="fw-bold text-success">
                      ${Number(v.total || 0).toFixed(2)}
                    </td>
                    <td>
                      <button 
                        className="btn btn-sm btn-outline-info rounded-pill px-3"
                        onClick={() => setVentaSeleccionada(v)}
                      >
                        <FaEye className="me-1" /> Ver Detalle
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" className="py-5 text-center text-muted">
                    No se encontraron ventas registradas.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* ✅ MODAL DE DETALLE DE VENTA */}
      {ventaSeleccionada && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)" }}>
          <div className="modal-dialog modal-lg modal-dialog-centered">
            <div className="modal-content border-0 shadow-lg rounded-4">
              <div className="modal-header bg-primary text-white border-0 p-4">
                <h5 className="modal-title fw-bold">
                  <FaFileInvoiceDollar className="me-2" /> 
                  Detalle de Venta #{ventaSeleccionada._id?.slice(-6).toUpperCase()}
                </h5>
                <button className="btn-close btn-close-white" onClick={() => setVentaSeleccionada(null)}></button>
              </div>
              <div className="modal-body p-4">
                <div className="row mb-4">
                  <div className="col-md-6">
                    <h6 className="text-muted small text-uppercase fw-bold">Información del Cliente</h6>
                    <p className="mb-1 fw-bold fs-5">{ventaSeleccionada.cliente_id?.nombre || "Consumidor Final"}</p>
                    <p className="text-muted mb-0 small">{ventaSeleccionada.cliente_id?.email || "Sin correo registrado"}</p>
                  </div>
                  <div className="col-md-6 text-md-end">
                    <h6 className="text-muted small text-uppercase fw-bold">Fecha de Emisión</h6>
                    <p className="mb-0">{new Date(ventaSeleccionada.createdAt).toLocaleString()}</p>
                  </div>
                </div>

                <h6 className="text-muted small text-uppercase fw-bold mb-3">Productos Vendidos</h6>
                <div className="table-responsive bg-light rounded-3 p-2">
                  <table className="table table-borderless align-middle mb-0">
                    <thead className="border-bottom">
                      <tr>
                        <th>Producto</th>
                        <th className="text-center">Cant.</th>
                        <th className="text-end">Precio</th>
                        <th className="text-end">Subtotal</th>
                      </tr>
                    </thead>
                    <tbody>
                      {/* ✅ Mapeamos los productos que vienen dentro de la venta */}
                      {(ventaSeleccionada.productos || []).map((p, index) => (
                        <tr key={index}>
                          <td>
                            <FaBox className="me-2 text-muted small" />
                            {p.nombre || p.Nombre}
                          </td>
                          <td className="text-center">{p.cantidad || p.Cantidad}</td>
                          <td className="text-end">${Number(p.precio || 0).toFixed(2)}</td>
                          <td className="text-end fw-bold">${Number(p.subtotal || 0).toFixed(2)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                <div className="row mt-4 justify-content-end">
                  <div className="col-md-4">
                    <div className="d-flex justify-content-between mb-2">
                      <span className="text-muted">Subtotal:</span>
                      <span>${Number(ventaSeleccionada.subtotal || 0).toFixed(2)}</span>
                    </div>
                    <div className="d-flex justify-content-between mb-2">
                      <span className="text-muted">IVA (13%):</span>
                      <span>${Number(ventaSeleccionada.iva || 0).toFixed(2)}</span>
                    </div>
                    <div className="d-flex justify-content-between border-top pt-2 fw-bold fs-5 text-success">
                      <span>Total:</span>
                      <span>${Number(ventaSeleccionada.total || 0).toFixed(2)}</span>
                    </div>
                  </div>
                </div>
              </div>
              <div className="modal-footer border-0 p-4">
                <button className="btn btn-secondary rounded-pill px-4" onClick={() => setVentaSeleccionada(null)}>Cerrar</button>
                <button className="btn btn-primary rounded-pill px-4" onClick={() => window.print()}>🖨️ Imprimir Copia</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* 📄 CONTROLES DE PAGINACIÓN */}
      <div className="d-flex justify-content-center mt-4">
        <Pagination
          totalItems={ventas.length}
          itemsPerPage={itemsPerPage}
          currentPage={currentPage}
          onPageChange={setCurrentPage}
        />
      </div>
    </div>
  );
}
